"use client";

import type { XOR } from "ts-xor";

import { Checkbox as ShadcnCheckbox } from "@acme/ui/shadcn/checkbox";

import type { CheckboxProps } from "./checkbox";
import { Checkbox as InternalCheckbox } from "./checkbox";
import { CheckboxGroup } from "./checkbox-group";

export * from "./checkbox";
export * from "./checkbox-group";

type ShadcnCheckboxProps = Omit<
  React.ComponentProps<typeof ShadcnCheckbox>,
  "onChange"
>;

type XORCheckboxProps = XOR<CheckboxProps, ShadcnCheckboxProps>;

const ConditionCheckbox = (props: XORCheckboxProps) => {
  const isShadcnCheckbox = props.onCheckedChange !== undefined;

  if (isShadcnCheckbox) {
    return <ShadcnCheckbox {...props} />;
  }

  return <InternalCheckbox {...(props as CheckboxProps)} />;
};

type InternalCheckboxType = typeof ConditionCheckbox;

type CompoundedComponent = InternalCheckboxType & {
  Group: typeof CheckboxGroup;
};
const Checkbox = ConditionCheckbox as unknown as CompoundedComponent;

Checkbox.Group = CheckboxGroup;

export { Checkbox };
export { CheckboxGroup } from "./checkbox-group";

export { type CheckboxProps } from "./checkbox";

import * as React from "react";

import { cn } from "@acme/ui/lib/utils";
import { Checkbox as ShadcnCheckbox } from "@acme/ui/shadcn/checkbox";

import type { FormValueType } from "../form";
import type { CheckboxGroupContext } from "./group-context";
import { devUseWarning } from "../_util/warning";
import Wave from "../../lib/wave";
import { LoadingIcon } from "../button";
import { ConfigContext } from "../config-provider/context";
import DisabledContext from "../config-provider/disabled-context";
import { inputDisabledVariants } from "../input";
import GroupContext from "./group-context";
import useBubbleLock from "./use-bubble-lock";

type AbstractCheckboxProps<
  TChangeEvent,
  TValue extends FormValueType = FormValueType,
> = {
  id?: string;
  name?: string;

  // value
  value?: TValue;
  checked?: boolean;
  defaultChecked?: boolean;
  onChange?: (e: TChangeEvent) => void;
  onClick?: React.MouseEventHandler<HTMLElement>;
  onMouseEnter?: React.MouseEventHandler<HTMLElement>;
  onMouseLeave?: React.MouseEventHandler<HTMLElement>;

  // state
  disabled?: boolean;
  loading?: boolean;

  // styles
  style?: React.CSSProperties;
  className?: string;
  classNames?: {
    label?: string;
  };

  // render
  children?: React.ReactNode;

  // config
  skipGroup?: boolean;
};
export interface CheckboxChangeEventTarget<
  TValue extends FormValueType = FormValueType,
> extends Omit<CheckboxProps<TValue>, "value"> {
  checked: boolean;
  name?: string;
  type: "checkbox" | "radio";
  value: TValue;
}

export interface CheckboxChangeEvent<
  TValue extends FormValueType = FormValueType,
> {
  type: "change";
  target: CheckboxChangeEventTarget<TValue>;
  stopPropagation: () => void;
  preventDefault: () => void;
  nativeEvent: MouseEvent;
}

type CheckboxProps<TValue extends FormValueType = FormValueType> =
  AbstractCheckboxProps<CheckboxChangeEvent<TValue>, TValue> &
    React.AriaAttributes & {
      key?: React.Key; // fix warning when use key (shadcn)
      indeterminate?: boolean;
    };

function Checkbox<TValue extends FormValueType = FormValueType>(
  props: CheckboxProps<TValue>,
) {
  const {
    // id,
    // "aria-describedby": ariaDescribedBy,
    // "aria-invalid": ariaInvalid,

    value,

    loading,
    disabled,

    indeterminate = false,
    checked,
    defaultChecked,

    // styles
    style,
    className,
    classNames,
    // render
    children,

    skipGroup,

    // on
    // onClick,
    onChange,
    onMouseEnter,
    onMouseLeave,
    ...restProps
  } = props;

  const { direction, checkbox } = React.useContext(ConfigContext);
  const checkboxGroup = React.useContext(
    GroupContext as unknown as React.Context<CheckboxGroupContext<TValue> | null>,
  );
  const contextDisabled = React.useContext(DisabledContext);
  const mergedDisabled = checkboxGroup?.disabled ?? disabled ?? contextDisabled;

  const isGroup = !!(checkboxGroup && !skipGroup);

  if (process.env.NODE_ENV !== "production") {
    const warning = devUseWarning("Checkbox");

    warning(
      checked !== undefined || !!checkboxGroup || value === undefined,
      "usage",
      "`value` is not a valid prop, do you mean `checked`?",
    );
  }

  const mergedChecked = isGroup
    ? value === undefined
      ? false
      : !!checkboxGroup.value?.includes(value)
    : checked;

  const hasLabelContent = React.Children.toArray(children).some((child) => {
    if (typeof child === "boolean") {
      return false;
    }

    return child !== "";
  });

  // ============================ Event Lock ============================
  const [onLabelClick, onInputClick] = useBubbleLock(restProps.onClick);

  return (
    <Wave component="Checkbox" disabled={mergedDisabled}>
      <label
        className={cn(
          "inline-flex shrink-0 cursor-pointer items-baseline text-sm",
          direction === "rtl" ? "flex-row-reverse" : "flex-row",
          inputDisabledVariants({ disabled: mergedDisabled }),
          className,
        )}
        style={{ ...checkbox?.style, ...style }}
        onMouseEnter={onMouseEnter}
        onMouseLeave={onMouseLeave}
        onClick={onLabelClick}
      >
        <ShadcnCheckbox
          className={cn(
            "data-[state=indeterminate]:bg-muted",
            "self-center",
            "disabled:border-black/55 disabled:bg-black/15",
          )}
          value={value as string | undefined}
          checked={indeterminate ? "indeterminate" : mergedChecked}
          defaultChecked={defaultChecked}
          name={isGroup ? checkboxGroup.name : restProps.name}
          disabled={mergedDisabled}
          onClick={onInputClick}
          onCheckedChange={(nextChecked) => {
            onChange?.({
              type: "change",
              target: {
                type: "checkbox",
                name: isGroup ? checkboxGroup.name : restProps.name,
                value: value as unknown as TValue,
                checked: nextChecked === "indeterminate" ? false : nextChecked,
                indeterminate,
                // "aria-describedby": ariaDescribedBy,
                // "aria-invalid": ariaInvalid,
              },

              nativeEvent: new MouseEvent("change"),
              preventDefault: () => {
                //
              },
              stopPropagation: () => {
                //
              },
            });

            if (isGroup && checkboxGroup.toggleOption && value !== undefined) {
              checkboxGroup.toggleOption({ label: children, value });
            }
          }}
          {...restProps}
        />
        {loading ? (
          <LoadingIcon />
        ) : hasLabelContent ? (
          <span
            data-slot="checkbox-label"
            className={cn("leading-line-height px-2", classNames?.label)}
          >
            {children}
          </span>
        ) : null}
      </label>
    </Wave>
  );
}

export type { CheckboxProps, AbstractCheckboxProps };
export { Checkbox };

import { useMemo } from "react";
import { useControlledState } from "@rc-component/util";

import type { ButtonColorVariants } from "../button/button-variants";
import type { FormValueType } from "../form";
import type { CheckboxChangeEvent } from "./checkbox";
import { cn } from "../../lib/utils";
import { Checkbox } from "./checkbox";

export interface CheckboxOptionType<T extends FormValueType = FormValueType> {
  label: React.ReactNode;
  value: T;
  style?: React.CSSProperties;
  className?: string; // 👈 5.25.0+
  disabled?: boolean;
  title?: string;
  id?: string;
  onChange?: (e: CheckboxChangeEvent<T>) => void;
  required?: boolean;

  color?: ButtonColorVariants["color"];
}

export interface AbstractCheckboxGroupProps<
  T extends FormValueType = FormValueType,
> {
  options?: CheckboxOptionType<T>[];
  style?: React.CSSProperties;
  className?: string;
  classNames?: {
    item?: string;
    label?: string;
  };
  disabled?: boolean;
}

type CheckboxGroupProps<T extends FormValueType = FormValueType> =
  AbstractCheckboxGroupProps<T> & {
    name?: string;
    value?: T[];
    defaultValue?: T[];
    onChange?: (checkedValues: T[]) => void;
  };
const CheckboxGroup = <T extends FormValueType = FormValueType>({
  name,
  value,
  defaultValue,
  options = [],
  onChange,
  disabled,
  className,
  classNames,
}: CheckboxGroupProps<T>) => {
  const [internalValue, setInternalValue] = useControlledState(
    defaultValue,
    value,
  );

  const memoizedOptions = useMemo<CheckboxOptionType<T>[]>(
    () =>
      options.map((option) => {
        if (typeof option === "string" || typeof option === "number") {
          return { label: option, value: option } as CheckboxOptionType<T>;
        }
        return option;
      }),
    [options],
  );

  return (
    <div
      data-slot="checkbox-group"
      className={cn("inline-flex flex-wrap gap-2", className)}
    >
      {memoizedOptions.map((o) => {
        const isDisabled = o.disabled ?? disabled;
        return (
          <Checkbox
            key={o.value.toString()}
            name={name}
            checked={internalValue?.includes(o.value)}
            value={o.value as string}
            disabled={isDisabled}
            onChange={(e) => {
              if (isDisabled) return;

              const newValue = e.target.checked
                ? [...(internalValue ?? []), o.value]
                : internalValue?.filter((x) => x !== o.value);

              setInternalValue(newValue);
              onChange?.(newValue ?? []);
            }}
            className={cn(classNames?.item, o.className)}
            classNames={classNames}
          >
            {o.label}
          </Checkbox>
        );
      })}
    </div>
  );
};

export type { CheckboxGroupProps };
export { CheckboxGroup };

import React from "react";

import type { FormValueType } from "../form";
import type { CheckboxOptionType } from "./checkbox-group";

export interface CheckboxGroupContext<
  TValue extends FormValueType = FormValueType,
> {
  name?: string;
  toggleOption?: (option: CheckboxOptionType<TValue>) => void;
  value?: TValue[];
  disabled?: boolean;
  registerValue: (val: TValue) => void;
  cancelValue: (val: TValue) => void;
}

const GroupContext =
  React.createContext<CheckboxGroupContext<FormValueType> | null>(null);

export default GroupContext;

/* eslint-disable @typescript-eslint/no-non-null-assertion */
import React from "react";
import raf from "rc-util/es/raf";

/**
 * When click on the label,
 * the event will be stopped to prevent the label from being clicked twice.
 * label click -> input click -> label click again
 */
export default function useBubbleLock(
  onOriginInputClick?: React.MouseEventHandler<HTMLButtonElement>,
) {
  const labelClickLockRef = React.useRef<number | null>(null);

  const clearLock = () => {
    raf.cancel(labelClickLockRef.current!);
    labelClickLockRef.current = null;
  };

  const onLabelClick: React.MouseEventHandler<HTMLLabelElement> = () => {
    clearLock();

    labelClickLockRef.current = raf(() => {
      labelClickLockRef.current = null;
    });
  };

  const onInputClick: React.MouseEventHandler<HTMLButtonElement> = (e) => {
    if (labelClickLockRef.current) {
      e.stopPropagation();
      clearLock();
    }

    onOriginInputClick?.(e);
  };

  return [onLabelClick, onInputClick] as const;
}

"use client"

import * as React from "react"
import { Checkbox as CheckboxPrimitive } from "radix-ui"

import { cn } from "@acme/ui/lib/utils"
import { CheckIcon } from "lucide-react"

function Checkbox({
  className,
  ...props
}: React.ComponentProps<typeof CheckboxPrimitive.Root>) {
  return (
    <CheckboxPrimitive.Root
      data-slot="checkbox"
      className={cn(
        "peer relative flex size-4 shrink-0 items-center justify-center rounded-[4px] border border-input transition-colors outline-none group-has-disabled/field:opacity-50 after:absolute after:-inset-x-3 after:-inset-y-2 focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50 disabled:cursor-not-allowed disabled:opacity-50 aria-invalid:border-destructive aria-invalid:ring-3 aria-invalid:ring-destructive/20 aria-invalid:aria-checked:border-primary dark:bg-input/30 dark:aria-invalid:border-destructive/50 dark:aria-invalid:ring-destructive/40 data-checked:border-primary data-checked:bg-primary data-checked:text-primary-foreground dark:data-checked:bg-primary",
        className
      )}
      {...props}
    >
      <CheckboxPrimitive.Indicator
        data-slot="checkbox-indicator"
        className="grid place-content-center text-current transition-none [&>svg]:size-3.5"
      >
        <CheckIcon
        />
      </CheckboxPrimitive.Indicator>
    </CheckboxPrimitive.Root>
  )
}

export { Checkbox }
